import{_ as r,c as s,o,ae as n}from"./chunks/framework.Cqi9LMMK.js";const d=JSON.parse('{"title":"Инспектор","description":"","frontmatter":{"title":"Инспектор"},"headers":[],"relativePath":"props/inspect.md","filePath":"props/inspect.md"}'),e={name:"props/inspect.md"};function a(p,t,l,g,i,c){return o(),s("div",null,[...t[0]||(t[0]=[n('<h1 id="режим-inspect-выбор-компонента-на-странице" tabindex="-1">Режим Inspect (выбор компонента на странице) <a class="header-anchor" href="#режим-inspect-выбор-компонента-на-странице" aria-label="Permalink to &quot;Режим Inspect (выбор компонента на странице)&quot;">​</a></h1><p>Режим <strong>Inspect</strong> на вкладке <strong>Props</strong> позволяет указать интересующий фрагмент интерфейса <strong>прямо на странице</strong> и после клика сузить список компонентов до поддерева, связанного с выбранным узлом. По смыслу это близко к выбору элемента в инструментах разработчика браузера, но результат здесь — <strong>фильтрованная таблица Props</strong>, а не отдельная вкладка DOM.</p><p>Общее описание вкладки Props см. в разделе <a href="/docs/props/general.html">Основные возможности</a>.</p><hr><h2 id="запуск-и-остановка" tabindex="-1">Запуск и остановка <a class="header-anchor" href="#запуск-и-остановка" aria-label="Permalink to &quot;Запуск и остановка&quot;">​</a></h2><p>Кнопка <strong>Inspect</strong> находится на панели инструментов вкладки <strong>Props</strong> (иконка указателя). Подсказка к кнопке: выбрать элемент на странице, чтобы отфильтровать список.</p><p>Перед активацией режима список компонентов <strong>обновляется</strong> — чтобы метки на элементах и структура дерева соответствовали текущему состоянию страницы.</p><p>Повторное нажатие <strong>Inspect</strong> во время активного режима <strong>выключает</strong> прицел, не отменяя уже применённый фильтр по корню.</p><p><strong>Escape</strong> в фокусе панели инспектора отменяет режим выбора без выбора элемента (ввод с клавиатуры на самой странице в этом сценарии может не дойти до обработчика отмены — выход удобнее выполнять из панели или снова нажать <strong>Inspect</strong>).</p><p>При переключении вкладки инспектора или закрытии панели режим выбора <strong>сбрасывается</strong> автоматически.</p><hr><h2 id="поведение-на-странице" tabindex="-1">Поведение на странице <a class="header-anchor" href="#поведение-на-странице" aria-label="Permalink to &quot;Поведение на странице&quot;">​</a></h2><p>После включения Inspect поверх страницы включается режим <strong>захвата указателя</strong>: движение мыши и фиксация точки выбора обрабатываются так, чтобы можно было нацелиться и на элементы, которые обычно <strong>не получают клики</strong> (например, с атрибутами вроде «неактивен» или с отключёнными для указателя областями). Выбор привязывается не к произвольному DOM-узлу, а к ближайшему элементу, помеченному инспектором как связанный с <strong>инстансом Vue</strong>.</p><p>Пока курсор над страницей приложения, элемент под курсором <strong>подсвечивается</strong>, рядом может отображаться <strong>всплывающая подсказка</strong> с краткой информацией: имя компонента, условное описание корневого DOM-элемента (тег, фрагмент класса или id), число props и число дочерних связанных элементов. Тема подсказки (светлая или тёмная) согласуется с настройками инспектора.</p><p><strong>Панель Vue Inspector</strong> (оверлей, шеврон, плавающая информационная плашка режима Inspect) <strong>не участвует</strong> в выборе: над ними сохраняется обычный курсор и можно безопасно двигать или сворачивать интерфейс инспектора.</p><p>В настройках можно включить <strong>сворачивание оверлея</strong> на время режима Inspect, чтобы панель не перекрывала область страницы; после выбора элемента или отмены оверлей возвращается к прежнему виду (если эта опция включена).</p><hr><h2 id="результат-выбора" tabindex="-1">Результат выбора <a class="header-anchor" href="#результат-выбора" aria-label="Permalink to &quot;Результат выбора&quot;">​</a></h2><p>После <strong>клика</strong> по нужному элементу на странице:</p><ul><li>режим Inspect <strong>закрывается</strong>;</li><li>в таблице Props остаются компоненты, относящиеся к выбранному <strong>корню</strong> (поддерево относительно выбранного инстанса);</li><li>на панели появляется индикатор <strong>Filtered</strong> — напоминание, что список сужен по элементу.</li></ul><p>Нажатие на индикатор <strong>Filtered</strong> (или действие с тем же смыслом по подсказке) <strong>снимает</strong> привязку к элементу и снова показывает <strong>полный</strong> список компонентов после обновления данных.</p><p>Повторный запуск Inspect при уже активном фильтре по корню снова обновляет дерево <strong>в рамках</strong> текущего корня, затем позволяет выбрать другой узел и заменить фильтр.</p><hr><h2 id="ограничения-и-типичные-ситуации" tabindex="-1">Ограничения и типичные ситуации <a class="header-anchor" href="#ограничения-и-типичные-ситуации" aria-label="Permalink to &quot;Ограничения и типичные ситуации&quot;">​</a></h2><ul><li>Если под курсором нет помеченного Vue-элемента, выбор может не привязаться к компоненту — в этом случае проверьте, что на странице действительно отрендерены инстансы, видимые инспектору.</li><li>Сильно <strong>вложенные</strong> или <strong>нестандартные</strong> врапперы могут дать не тот компонент, который вы ожидали визуально: имеет смысл повторить выбор ближе к нужному видимому блоку или снять фильтр и воспользоваться поиском по имени в таблице.</li><li>Режим Inspect <strong>только сужает список</strong>; <strong>избранное</strong>, <strong>чёрный список</strong> и <strong>поиск</strong> по-прежнему работают поверх отфильтрованного набора. Подробности — на страницах <a href="/docs/props/favorite.html">Избранное</a> и <a href="/docs/props/blacklist.html">Чёрный список</a>.</li></ul><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/docs/props/general.html">Основные возможности Props</a></li><li><a href="/docs/props/favorite.html">Избранное</a></li><li><a href="/docs/props/blacklist.html">Чёрный список</a></li></ul>',28)])])}const u=r(e,[["render",a]]);export{d as __pageData,u as default};
